import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import response from './response.json';

interface CareSchedule {
  date: string;
  task: string;
  completed: boolean;
}

interface PlantCareData {
  plantName: string;
  nextWatering: string;
  soilMoisture: string;
  careSchedule: CareSchedule[];
}

export default function Widget() {
  const plantCareData = response.data as PlantCareData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h5" fontWeight={600} color="primary">
              {plantCareData.plantName}
            </Typography>
            <Typography variant="body2" color="text.secondary" sx={{ mb: 1 }}>
              Soil Moisture: {plantCareData.soilMoisture}
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Next Watering: {new Date(plantCareData.nextWatering).toLocaleDateString()}
            </Typography>
          </Box>

          <Divider />

          <Box>
            <Typography variant="subtitle1" fontWeight={500} sx={{ mb: 1 }}>
              Care Schedule
            </Typography>
            <Stack spacing={0.5}>
              {plantCareData.careSchedule.slice(0, 3).map((schedule, index) => (
                <Chip
                  key={index}
                  label={`${schedule.task} on ${new Date(schedule.date).toLocaleDateString()}`}
                  color={schedule.completed ? "primary" : "default"}
                  sx={{ fontSize: '12px', width: '100%' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
